28	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
29	
30	const sumBasePremiums = (items: Item[]): number =>
31	  items.reduce((sum, item) => sum + basePremium(item), 0);
32	
33	const quote = (step: QuoteStep): QuoteResult => ({
34	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
35	});
36	
37	export const runScenario = (scenario: Scenario): ScenarioResult => ({
38	  results: scenario.steps.map(quote),
